import React, { useState, useEffect } from 'react'; // Thêm useState, useEffect
import { Divider, List, ListItem, ListItemText, Typography } from '@mui/material';
import { Link } from 'react-router-dom';
import fetchModel from '../../lib/fetchModelData'; // Đổi import từ models sang fetchModel

function UserList() {
  const [users, setUsers] = useState([]); // State để lưu danh sách user

  useEffect(() => {
    // Gọi API lấy danh sách user
    fetchModel("/user/list")
      .then((response) => {
        setUsers(response.data); // Cập nhật state khi có dữ liệu
      })
      .catch((err) => console.error("Lỗi lấy danh sách user:", err));
  }, []); // [] đảm bảo chỉ gọi 1 lần khi load trang

  return (
    <div>
      <Typography variant="h6" style={{ padding: '10px' }}>Users</Typography>
      <List component="nav">
        {users.map((user) => (
          <React.Fragment key={user._id}>
            <ListItem button component={Link} to={`/users/${user._id}`}>
              <ListItemText primary={`${user.first_name} ${user.last_name}`} />
            </ListItem>
            <Divider />
          </React.Fragment>
        ))}
      </List>
    </div>
  );
}

export default UserList;
